module sr_latch(  
    input wire sr_latch_S,  
    input wire R,  
    output reg Q,  
    output reg Q_bar  
);  
    always @ (sr_latch_S, R) begin  
        if (sr_latch_S && ~R) begin  
            Q <= 1;  
            Q_bar <= 0;  
        end  
        else if (~sr_latch_S && R) begin  
            Q <= 0;  
            Q_bar <= 1;  
        end  
        // Invalid condition will keep the previous state  
    end  
endmodule
